    84→	const { tooltipBg, tooltipBorder, gridStroke, axisStroke } = useChartTheme();
    85→	const [selectedMetric, setSelectedMetric] = useState<MetricType>("sessions");
    86→	const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());
    87→	const toggleSeries = (key: string) =>
    88→		setHiddenSeries((prev) => {
