    91→			return next;
    92→		});
    93→
    94→	const currentMetric = METRICS[selectedMetric];
    95→
    96→	// Rank developers by total sessions (stable ordering across metric changes)
    97→	const { topDevelopers, topDevelopersSet, hasOther } = useMemo(() => {
    98→		const devTotals = new Map<string, number>();
    99→		for (const d of data) {
   100→			devTotals.set(d.user_id, (devTotals.get(d.user_id) ?? 0) + d.sessions);
   101→		}
   102→		const sorted = Array.from(devTotals.entries()).sort((a, b) => b[1] - a[1]);
   103→		const top = sorted.slice(0, MAX_SERIES).map(([u]) => u);
   104→		return {
   105→			topDevelopers: top,
   106→			topDevelopersSet: new Set(top),
   107→			hasOther: sorted.length > MAX_SERIES,
   108→		};
