   136→				}),
   137→			};
   138→
   139→			for (const userId of topDevelopers) {
   140→				const dp = data.find((d) => d.date === date && d.user_id === userId);
   141→				dateObj[userId] = dp
   142→					? (dp[currentMetric.key as keyof DeveloperTrendDataPoint] as number)
