   145→
   146→			if (showOther) {
   147→				dateObj.Other = data
   148→					.filter((d) => d.date === date && !topDevelopersSet.has(d.user_id))
   149→					.reduce(
   150→						(sum, d) =>
   151→							sum +
   152→							((d[
   153→								currentMetric.key as keyof DeveloperTrendDataPoint
   154→							] as number) ?? 0),
   155→						0,
   156→					);
   157→			}
   158→
   159→			return dateObj;
   160→		});
   161→
   162→		return { chartData, seriesList };
   163→	}, [
   164→		data,
   165→		topDevelopers,
   166→		topDevelopersSet,
   167→		hasOther,
   168→		selectedMetric,
   169→		currentMetric,
   170→	]);
   171→
   172→	const formatUsername = (userId: string) => {
   173→		if (userId === "Other") return "Other";
   174→		return userMap[userId] || userId.substring(0, 12);
   175→	};
   176→
   177→	return (
   178→		<div className="space-y-4">
   179→			<div className="flex flex-wrap gap-2">
   180→				{Object.entries(METRICS).map(([key, metric]) => {
   181→					const isSelected = selectedMetric === key;
   182→					const Icon = metric.icon;
   183→					return (
   184→						<button
   185→							type="button"
   186→							key={key}
   187→							onClick={() => setSelectedMetric(key as MetricType)}
   188→							className={`
   189→								flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium
   190→								transition-all duration-200
   191→								${
   192→									isSelected
   193→										? "bg-accent-light text-accent-text border-2 border-accent"
   194→										: "bg-surface text-muted border-2 border-transparent hover:bg-hover"
   195→								}
   196→							`}
   197→						>
   198→							<Icon className="w-4 h-4" />
   199→							<span>{metric.label}</span>
   200→							{"tooltip" in metric && metric.tooltip && (
   201→								// biome-ignore lint/a11y/noStaticElementInteractions: tooltip stop-propagation wrapper
   202→								// biome-ignore lint/a11y/useKeyWithClickEvents: tooltip stop-propagation wrapper
   203→								<span onClick={(e) => e.stopPropagation()}>
   204→									<InfoTooltip text={metric.tooltip as string} />
   205→								</span>
   206→							)}
   207→						</button>
   208→					);
   209→				})}
   210→			</div>
   211→
   212→			<ResponsiveContainer width="100%" height={400}>
   213→				{selectedMetric === "success_rate" ? (
   214→					<LineChart
   215→						data={chartData}
   216→						margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
   217→					>
   218→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   219→						<XAxis
   220→							dataKey="displayDate"
   221→							stroke={axisStroke}
   222→							style={{ fontSize: "12px" }}
   223→							angle={-45}
   224→							textAnchor="end"
   225→							height={80}
   226→							tickMargin={8}
   227→						/>
   228→						<YAxis
   229→							stroke={axisStroke}
   230→							style={{ fontSize: "12px" }}
   231→							tickFormatter={currentMetric.formatter}
   232→							domain={[0, 100]}
   233→						/>
   234→						<Tooltip
   235→							contentStyle={{
